#include<bits/stdc++.h>
using namespace std;
struct node
{
    double x,y;
    bool operator<(const node&b)const
    {
        return(x==b.x?y<b.y:x<b.x);
    }
    node operator+(const node&b)const
    {
        return (node){x+b.x,y+b.y};
    }
}a[100010],q[100010];
node rotate(node a,double t)
{
    double c=cos(t),s=sin(t);
    return (node){a.x*c-a.y*s,a.x*s+a.y*c};
}
double dis(node i,node j)
{
    return sqrt(pow(i.x-j.x,2)+pow(i.y-j.y,2));
}
int main()
{
    int tot=0;
    int n;
    scanf("%d",&n);
    double a,b,r;
    scanf("%lf%lf%lf",&b,&a,&r);
    a/=2.0;
    b/=2.0;
    for(int i=1;i<=n;i++)
    {
        double x,y,the;
        scanf("%lf%lf%lf",&x,&y,&the);
        x+=(1e-12);
        y+=(1e-12);
        the+=(1e-12);
        node p=(node){x,y};
        ::a[++tot]=rotate((node){a-r,b-r},the)+p;
        ::a[++tot]=rotate((node){r-a,b-r},the)+p;
        ::a[++tot]=rotate((node){a-r,r-b},the)+p;
        ::a[++tot]=rotate((node){r-a,r-b},the)+p;
    }
    n=tot;
    sort(::a+1,::a+1+n);
    tot=0;
    q[++tot]=::a[1];
    for(int i=2;i<=n;i++)
    {
        while(tot>=2&&(::a[i].y-q[tot].y)*(q[tot].x-q[tot-1].x)>=(q[tot].y-q[tot-1].y)*(::a[i].x-q[tot].x))
        {
            tot--;
        }
        q[++tot]=::a[i];
    }
    double ans=0;
    for(int i=1;i<tot;i++)
    {
        ans+=dis(q[i],q[i+1]);
    }
    q[tot=1]=::a[n];
    for(int i=n-1;i>=1;i--)
    {
        while(tot>=2&&(::a[i].y-q[tot].y)*(q[tot].x-q[tot-1].x)>=(q[tot].y-q[tot-1].y)*(::a[i].x-q[tot].x))
        {
            tot--;
        }
        q[++tot]=::a[i];
    }
    ans+=2*3.141592653589793*r;
    for(int i=1;i<tot;i++)
    {
        ans+=dis(q[i],q[i+1]);
    }
    printf("%.2lf\n",ans);
    return 0;
}
